int backtrack(int index, int currentSum, bool taken,
              vector<int>& nums, int k) {

    // Base case
    if (index == nums.size()) {
        return (currentSum == k && taken) ? 1 : 0;
    }

    // Include current element
    int include = backtrack(
        index + 1,
        currentSum + nums[index],
        true,
        nums,
        k
    );

    // Exclude current element
    int exclude = backtrack(
        index + 1,
        currentSum,
        taken,
        nums,
        k
    );

    return include + exclude;
}

int countSubsequences(vector<int>& nums, int k) {
    return backtrack(0, 0, false, nums, k);
}

